const t=[{id:"tkt-001",subject:"Shipping delay for container MEDU1234568",status:"closed",priority:"high",category:"shipping",author_id:"usr-008",author_name:"Mariam Janelidze",assigned_to:"usr-003",messages:[{id:"msg-001-1",ticket_id:"tkt-001",author_id:"usr-008",author_name:"Mariam Janelidze",author_avatar:"https://i.pravatar.cc/150?u=user8",author_role:"dealer",content:"Container MEDU1234568 carrying the 2024 BMW 330i was supposed to arrive by March 20 but there is no tracking update since February 28. The customer is asking daily. Can you check with the shipping line?",attachments:[],created_at:"2026-02-15T09:00:00Z"},{id:"msg-001-2",ticket_id:"tkt-001",author_id:"usr-003",author_name:"Davit Tsiklauri",author_avatar:"https://i.pravatar.cc/150?u=user3",author_role:"manager",content:"I contacted MSC shipping. The vessel had a port congestion delay in Suez. They confirmed the new ETA is March 30. I will update the system now.",attachments:[],created_at:"2026-02-16T14:30:00Z"},{id:"msg-001-3",ticket_id:"tkt-001",author_id:"usr-008",author_name:"Mariam Janelidze",author_avatar:"https://i.pravatar.cc/150?u=user8",author_role:"dealer",content:"Thank you for the quick response. I have informed the customer about the delay. He is fine with the new date. Please close this ticket.",attachments:[],created_at:"2026-02-17T10:00:00Z"},{id:"msg-001-4",ticket_id:"tkt-001",author_id:"usr-002",author_name:"Nino Kvaratskhelia",author_avatar:"https://i.pravatar.cc/150?u=user2",author_role:"admin",content:"Noted. ETA updated in the system. Closing this ticket. If there are further delays, please open a new one.",attachments:[],created_at:"2026-02-22T16:00:00Z"}],created_at:"2026-02-15T09:00:00Z",updated_at:"2026-02-22T16:00:00Z"},{id:"tkt-002",subject:"Invoice discrepancy INV-2024-005",status:"answered",priority:"medium",category:"billing",author_id:"usr-008",author_name:"Mariam Janelidze",assigned_to:"usr-004",messages:[{id:"msg-002-1",ticket_id:"tkt-002",author_id:"usr-008",author_name:"Mariam Janelidze",author_avatar:"https://i.pravatar.cc/150?u=user8",author_role:"dealer",content:"The customer Tamar Basilaia noticed that Invoice INV-2024-005 includes a $300 EV Battery Inspection Fee that was not discussed. The proforma she received initially only had the car price and transport. Can we remove this charge or justify it?",attachments:[],created_at:"2026-02-25T10:00:00Z"},{id:"msg-002-2",ticket_id:"tkt-002",author_id:"usr-004",author_name:"Tamari Lomidze",author_avatar:"https://i.pravatar.cc/150?u=user4",author_role:"manager",content:"The EV Battery Inspection Fee is a standard charge for all Tesla vehicles. It covers the mandatory HV battery health check required by Georgian customs. I can provide the customer with our fee schedule document. However, I agree it should have been communicated upfront.",attachments:["https://placehold.co/400x300/1a1a2e/white?text=Fee+Schedule"],created_at:"2026-02-25T15:00:00Z"},{id:"msg-002-3",ticket_id:"tkt-002",author_id:"usr-008",author_name:"Mariam Janelidze",author_avatar:"https://i.pravatar.cc/150?u=user8",author_role:"dealer",content:"I shared the fee schedule with the customer. She wants a 50% discount on this fee as a goodwill gesture since it was not mentioned earlier. Can we approve a $150 credit?",attachments:[],created_at:"2026-02-26T09:30:00Z"},{id:"msg-002-4",ticket_id:"tkt-002",author_id:"usr-004",author_name:"Tamari Lomidze",author_avatar:"https://i.pravatar.cc/150?u=user4",author_role:"manager",content:"Approved. I will issue a partial credit of $150 to the invoice. Please inform the customer. Going forward, always include the EV inspection fee in Tesla proformas.",attachments:[],created_at:"2026-02-26T14:00:00Z"}],created_at:"2026-02-25T10:00:00Z",updated_at:"2026-02-26T14:00:00Z"},{id:"tkt-003",subject:"Car damage on arrival - Hyundai Palisade",status:"waiting",priority:"urgent",category:"damage",author_id:"usr-006",author_name:"Ana Gogoladze",assigned_to:"usr-001",messages:[{id:"msg-003-1",ticket_id:"tkt-003",author_id:"usr-006",author_name:"Ana Gogoladze",author_avatar:"https://i.pravatar.cc/150?u=user6",author_role:"dealer",content:"The 2021 Hyundai Palisade Limited (car-024) arrived at Poti with additional damage not present in the pre-shipping photos. The front bumper is cracked and the driver side mirror is broken. This was not in the auction photos or our pre-load inspection. The customer is refusing to accept delivery.",attachments:["https://placehold.co/400x300/1a1a2e/white?text=Damage+Photo+1","https://placehold.co/400x300/1a1a2e/white?text=Damage+Photo+2"],created_at:"2026-01-22T08:00:00Z"},{id:"msg-003-2",ticket_id:"tkt-003",author_id:"usr-001",author_name:"Giorgi Beridze",author_avatar:"https://i.pravatar.cc/150?u=user1",author_role:"admin",content:"I reviewed the pre-shipping photos and confirm this damage occurred during transit. I am filing a claim with the shipping insurance. In the meantime, please get quotes for bumper and mirror replacement from our partner shop in Poti. We will cover the repair cost.",attachments:[],created_at:"2026-01-22T11:30:00Z"},{id:"msg-003-3",ticket_id:"tkt-003",author_id:"usr-006",author_name:"Ana Gogoladze",author_avatar:"https://i.pravatar.cc/150?u=user6",author_role:"dealer",content:"Got the quote: bumper replacement $320, mirror replacement $180, paint and labor $250. Total $750. The customer said he would accept if we cover the full repair and issue a $1,500 credit note for the inconvenience. Attached is the shop estimate.",attachments:["https://placehold.co/400x300/1a1a2e/white?text=Repair+Estimate"],created_at:"2026-01-23T14:00:00Z"},{id:"msg-003-4",ticket_id:"tkt-003",author_id:"usr-001",author_name:"Giorgi Beridze",author_avatar:"https://i.pravatar.cc/150?u=user1",author_role:"admin",content:"We will cover the $750 repair. Regarding the $1,500 credit note, I have approved it since we want to keep the customer relationship. Credit note INV-2024-024 has been issued. Please proceed with the repair and update the customer.",attachments:[],created_at:"2026-01-24T09:00:00Z"},{id:"msg-003-5",ticket_id:"tkt-003",author_id:"usr-006",author_name:"Ana Gogoladze",author_avatar:"https://i.pravatar.cc/150?u=user6",author_role:"dealer",content:"Repair is underway at the Poti shop. Expected completion in 3 days. The customer has accepted the credit note and is satisfied with the resolution. Will update once the car is ready for pickup.",attachments:[],created_at:"2026-02-28T11:00:00Z"}],created_at:"2026-01-22T08:00:00Z",updated_at:"2026-02-28T11:00:00Z"},{id:"tkt-004",subject:"Container booking confirmation needed - RAV4",status:"opened",priority:"medium",category:"shipping",author_id:"usr-009",author_name:"Irakli Datunashvili",assigned_to:"usr-003",messages:[{id:"msg-004-1",ticket_id:"tkt-004",author_id:"usr-009",author_name:"Irakli Datunashvili",author_avatar:"https://i.pravatar.cc/150?u=user9",author_role:"dealer",content:"The 2022 Toyota RAV4 XLE (car-013) has been purchased at IAAI Houston but has no booking number yet. The customer is pressing for a shipping timeline. Can we get this booked on the next available container from Houston?",attachments:[],created_at:"2026-03-03T10:00:00Z"},{id:"msg-004-2",ticket_id:"tkt-004",author_id:"usr-003",author_name:"Davit Tsiklauri",author_avatar:"https://i.pravatar.cc/150?u=user3",author_role:"manager",content:"The next available container from Houston departs March 15. I need the auction release documents to proceed with booking. Has IAAI released the title yet?",attachments:[],created_at:"2026-03-03T14:30:00Z"}],created_at:"2026-03-03T10:00:00Z",updated_at:"2026-03-03T14:30:00Z"},{id:"tkt-005",subject:"Wrong VIN on customs declaration",status:"answered",priority:"high",category:"general",author_id:"usr-007",author_name:"Zurab Kapanadze",assigned_to:"usr-001",messages:[{id:"msg-005-1",ticket_id:"tkt-005",author_id:"usr-007",author_name:"Zurab Kapanadze",author_avatar:"https://i.pravatar.cc/150?u=user7",author_role:"dealer",content:'The customs declaration for the 2018 Toyota Highlander (car-022) has a typo in the VIN. The last digit shows "2" but the actual VIN ends in "1". This is blocking the customs clearance at Poti. Need urgent correction.',attachments:["https://placehold.co/400x300/1a1a2e/white?text=Customs+Doc"],created_at:"2026-01-08T08:00:00Z"},{id:"msg-005-2",ticket_id:"tkt-005",author_id:"usr-001",author_name:"Giorgi Beridze",author_avatar:"https://i.pravatar.cc/150?u=user1",author_role:"admin",content:"I contacted our customs broker. They are filing an amendment with Revenue Service. Typically takes 1-2 business days. I have also corrected the VIN in our system. The customer should expect clearance by January 10.",attachments:[],created_at:"2026-01-08T11:00:00Z"},{id:"msg-005-3",ticket_id:"tkt-005",author_id:"usr-007",author_name:"Zurab Kapanadze",author_avatar:"https://i.pravatar.cc/150?u=user7",author_role:"dealer",content:"Thank you, the amendment was processed and customs cleared the car on January 9. Customer picked it up. All good now.",attachments:[],created_at:"2026-01-10T09:00:00Z"}],created_at:"2026-01-08T08:00:00Z",updated_at:"2026-01-10T09:00:00Z"},{id:"tkt-006",subject:"Request for additional port photos - Tesla Model 3",status:"opened",priority:"low",category:"general",author_id:"usr-008",author_name:"Mariam Janelidze",assigned_to:"usr-004",messages:[{id:"msg-006-1",ticket_id:"tkt-006",author_id:"usr-008",author_name:"Mariam Janelidze",author_avatar:"https://i.pravatar.cc/150?u=user8",author_role:"dealer",content:"Customer Tamar Basilaia is asking for pre-loading photos of her 2024 Tesla Model 3 (car-005) before it gets loaded onto the container. She wants to verify the condition matches the auction listing. Can our Houston yard agent take photos?",attachments:[],created_at:"2026-03-04T14:00:00Z"},{id:"msg-006-2",ticket_id:"tkt-006",author_id:"usr-004",author_name:"Tamari Lomidze",author_avatar:"https://i.pravatar.cc/150?u=user4",author_role:"manager",content:"I have forwarded the request to our yard agent in New York. Note: this Tesla is at the NJ yard, not Houston. They usually take 24 hours to send photos. I will upload them to the car record once received.",attachments:[],created_at:"2026-03-04T16:30:00Z"}],created_at:"2026-03-04T14:00:00Z",updated_at:"2026-03-04T16:30:00Z"},{id:"tkt-007",subject:"Overcharged transport fee on Honda CR-V",status:"closed",priority:"medium",category:"billing",author_id:"usr-009",author_name:"Irakli Datunashvili",assigned_to:"usr-004",messages:[{id:"msg-007-1",ticket_id:"tkt-007",author_id:"usr-009",author_name:"Irakli Datunashvili",author_avatar:"https://i.pravatar.cc/150?u=user9",author_role:"dealer",content:"Customer Nodar Shanidze is questioning the $1,400 transport fee on Invoice INV-2024-020 for the Honda CR-V. Our published rate for Savannah to Poti is $1,200 for vehicles under 1,600 kg. The CR-V weighs about 1,500 kg. Can we check?",attachments:[],created_at:"2026-01-12T10:00:00Z"},{id:"msg-007-2",ticket_id:"tkt-007",author_id:"usr-004",author_name:"Tamari Lomidze",author_avatar:"https://i.pravatar.cc/150?u=user4",author_role:"manager",content:"You are correct. The CR-V should have been charged $1,200 based on the Savannah to Poti tariff for its weight class. The $1,400 was the rate for the heavier tier. I will issue a $200 refund to the customer.",attachments:[],created_at:"2026-01-12T14:00:00Z"},{id:"msg-007-3",ticket_id:"tkt-007",author_id:"usr-009",author_name:"Irakli Datunashvili",author_avatar:"https://i.pravatar.cc/150?u=user9",author_role:"dealer",content:"Customer confirmed receipt of the $200 refund. He is happy. Thank you for the quick resolution. Please close the ticket.",attachments:[],created_at:"2026-01-15T11:00:00Z"},{id:"msg-007-4",ticket_id:"tkt-007",author_id:"usr-004",author_name:"Tamari Lomidze",author_avatar:"https://i.pravatar.cc/150?u=user4",author_role:"manager",content:"Glad it is resolved. I have also updated our internal process to auto-check weight tiers before invoice generation. Closing ticket.",attachments:[],created_at:"2026-01-15T14:30:00Z"}],created_at:"2026-01-12T10:00:00Z",updated_at:"2026-01-15T14:30:00Z"},{id:"tkt-008",subject:"Missing keys for Porsche Cayenne delivery",status:"waiting",priority:"high",category:"damage",author_id:"usr-005",author_name:"Levan Mchedlishvili",assigned_to:"usr-001",messages:[{id:"msg-008-1",ticket_id:"tkt-008",author_id:"usr-005",author_name:"Levan Mchedlishvili",author_avatar:"https://i.pravatar.cc/150?u=user5",author_role:"dealer",content:'The 2022 Porsche Cayenne S (car-008) was delivered to Poti but the keys are missing from the car. The auction listing stated "keys included" and our yard photos show keys on the dashboard. They must have been lost or stolen during shipping.',attachments:["https://placehold.co/400x300/1a1a2e/white?text=Yard+Photo+Keys"],created_at:"2026-02-10T09:00:00Z"},{id:"msg-008-2",ticket_id:"tkt-008",author_id:"usr-001",author_name:"Giorgi Beridze",author_avatar:"https://i.pravatar.cc/150?u=user1",author_role:"admin",content:"This is a serious issue. I am filing a complaint with the shipping line and requesting CCTV footage from the port. In the meantime, I have contacted our Porsche dealer partner in Tbilisi for replacement key programming. Cost estimate is $450-600 for a new key set.",attachments:[],created_at:"2026-02-10T14:00:00Z"},{id:"msg-008-3",ticket_id:"tkt-008",author_id:"usr-005",author_name:"Levan Mchedlishvili",author_avatar:"https://i.pravatar.cc/150?u=user5",author_role:"dealer",content:"Customer Archil Gabrichidze is upset but understands these things happen. He is asking us to cover the key replacement cost since it was not his fault. Can we approve this?",attachments:[],created_at:"2026-02-11T10:30:00Z"},{id:"msg-008-4",ticket_id:"tkt-008",author_id:"usr-001",author_name:"Giorgi Beridze",author_avatar:"https://i.pravatar.cc/150?u=user1",author_role:"admin",content:"Approved. We will cover the full key replacement cost. I have also escalated the claim with the shipping insurance. If the claim is successful, we get reimbursed. Please schedule the key programming at the Porsche dealer and send me the final invoice.",attachments:[],created_at:"2026-02-12T08:00:00Z"}],created_at:"2026-02-10T09:00:00Z",updated_at:"2026-02-12T08:00:00Z"}];export{t as tickets};
